// A simplified shape of the core data model
interface Shipment {
  id: string;
  customerId: string;
  legs: ShipmentLeg[];
  status: "quoted" | "booked" | "in_transit" | "delivered";
}

interface ShipmentLeg {
  id: string;
  carrier: string;
  origin: string;
  destination: string;
  status: "pending" | "picked_up" | "in_transit" | "delivered";
  documents: string[];
}

// Example permission check for updating a shipment leg
function canUpdateLeg(user: User, leg: ShipmentLeg): boolean {
  if (user.role === "admin") return true;
  if (user.role === "dispatcher") return leg.status !== "delivered";
  if (user.role === "carrier_partner") {
    return user.carrierId === leg.carrier && leg.status === "in_transit";
  }
  return false;
}
